    private readonly IDispatcher _dispatcher;

    public EventDispatcher(IDispatcher dispatcher)
    {
        _dispatcher = dispatcher;
    }

    public async Task DispatchEvents(List<EventDescriptor> eventDescriptors, IData data, Guid aggregateId)
