function longestSubstringWithTwoDistinct(s) {
  let start = 0;
  let maxLen = 0;
  let charMap = new Map();

  for (let end = 0; end < s.length; end++) {
    charMap.set(s[end], (charMap.get(s[end]) || 0) + 1);

    while (charMap.size > 2) {
      charMap.set(s[start], charMap.get(s[start]) - 1);
      if (charMap.get(s[start]) === 0) {
        charMap.delete(s[start]);
      }
      start++;
    }

    maxLen = Math.max(maxLen, end - start + 1);
  }

  return s.substr(start, maxLen);
}

// Test
console.log(longestSubstringWithTwoDistinct("abaccc")); // Output: "abac"
```

