use std::sync::mpsc::{sync_channel, SyncSender, Receiver};

fn zero_read_write_pipe() {
    let (tx, rx): (SyncSender<String>, Receiver<String>) = sync_channel(0);

    // Write message to the write end of the pipe
    tx.send("Hello, Pipe!".to_string()).unwrap();

    // Read message from the read end of the pipe
