using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;
using System;
using System.Diagnostics;
using System.IO;
using System.Text;
using System.Threading.Tasks;

namespace CustomMiddleware
{
    public class RequestLoggingMiddleware
    {
        private readonly RequestDelegate _next;
        private readonly ILogger<RequestLoggingMiddleware> _logger;

        public RequestLoggingMiddleware(RequestDelegate next, ILogger<RequestLoggingMiddleware> logger)
        {
            _next = next;
            _logger = logger;
        }

        public async Task Invoke(HttpContext context)
        {
            var sw = Stopwatch.StartNew();
            var request = context.Request;

            // Log request details
            _logger.LogInformation($"Request: {request.Method} {request.Path} received at {DateTime.Now}");

            // Process the request
            await _next(context);

            // Log processing time
            sw.Stop();
            _logger.LogInformation($"Request: {request.Method} {request.Path} processed in {sw.ElapsedMilliseconds} ms");
        }
    }

    public static class RequestLoggingMiddlewareExtensions
    {
        public static IApplicationBuilder UseRequestLogging(this IApplicationBuilder builder)
        {
            return builder.UseMiddleware<RequestLoggingMiddleware>();
        }
    }
}
```

In the solution, the `Invoke` method of the `RequestLoggingMiddleware` class logs the request details and processing time using the provided `ILogger` instance. The `UseRequestLogging` method in the `RequestLoggingMiddlewareExtensions` class integrates the custom middleware into the ASP.NET Core application's request processing pipeline.

