import uk.jixun.project.Simulator.Context.IExecutionContext;
import uk.jixun.project.Util.FifoList;

public class SimpleEvaluator implements MockEvaluate {
  @Override
  public void evaluate(FifoList<Integer> stack, IExecutionContext ctx) throws Exception {
    if (stack.size() < 2) {
      throw new IllegalStateException("Insufficient operands on the stack");
    }

    int operand2 = stack.pop();
    int operand1 = stack.pop();
    int result;

    // Perform arithmetic operations based on the context
    switch (ctx.getOperation()) {
      case ADD:
        result = operand1 + operand2;
        break;
      case SUBTRACT:
        result = operand1 - operand2;
        break;
      case MULTIPLY:
        result = operand1 * operand2;
        break;
      case DIVIDE:
        if (operand2 == 0) {
          throw new ArithmeticException("Division by zero");
        }
        result = operand1 / operand2;
        break;
      default:
        throw new UnsupportedOperationException("Unsupported operation");
    }

    stack.push(result);
  }
}
```

In the solution, we implement the `evaluate` method of the `MockEvaluate` interface. We first check if there are at least two operands on the stack. Then, we pop the top two elements from the stack and perform the specified arithmetic operation based on the context provided. We handle potential exceptions such as division by zero and unsupported operations. Finally, we push the result back onto the stack.

