use ring::agreement;
use ring::rand;

fn compute_shared_secret(my_private_key: &[u8], their_public_key: &[u8]) -> Result<Vec<u8>, String> {
    let my_private_key = agreement::EphemeralPrivateKey::from_bytes(my_private_key)
        .map_err(|e| format!("Invalid private key: {}", e))?;
    let their_public_key = agreement::UnparsedPublicKey::new(&agreement::X25519, their_public_key);

    let rng = rand::SystemRandom::new();
    let shared_secret = agreement::agree_ephemeral(my_private_key, &their_public_key, ring::error::Unspecified, |key_material| {
        Ok(key_material.to_vec())
    }).map_err(|e| format!("Key agreement failed: {}", e))?;

    Ok(shared_secret)
}
