function filterClusters(clusters) {
  // Remove clusters with class '.hidden'
  const filteredClusters = clusters.filter(cluster => !cluster.classList.contains('hidden'));

  // Sort the remaining clusters based on data-id in ascending order
  filteredClusters.sort((a, b) => {
    const idA = parseInt(a.dataset.id);
    const idB = parseInt(b.dataset.id);
    return idA - idB;
  });

  return filteredClusters;
}
