```rust
fn applyTransformation(grid: &mut Vec<Vec<i32>>) -> &Vec<Vec<i32>> {
    for i in 0..grid.len() {
        if grid[i][0] == 0 {
            for j in 0..grid[i].len() {
                if grid[i][j] == 1 {
                    grid[i][j] = 0;
                } else {
                    grid[i][j] = 1;
                }
            }
        }
    }
    grid
}
```

