import re

def extract_revision_identifiers(code_snippet):
    revision_pattern = r"revision\s*=\s*'(\w+)'"
    down_revision_pattern = r"down_revision\s*=\s*'(\w+)'"

    revision_match = re.search(revision_pattern, code_snippet)
    down_revision_match = re.search(down_revision_pattern, code_snippet)

    if revision_match and down_revision_match:
        revision_identifier = revision_match.group(1)
        down_revision_identifier = down_revision_match.group(1)
        return {'revision': revision_identifier, 'down_revision': down_revision_identifier}
    else:
        return {'revision': None, 'down_revision': None}
