import json

class GraphManager:
    def __init__(self):
        self.graph = {
            'nodes': [],
            'edges': []
        }

    def add_node(self, node_id):
        if node_id not in self.graph['nodes']:
            self.graph['nodes'].append(node_id)

    def remove_node(self, node_id):
        if node_id in self.graph['nodes']:
            self.graph['nodes'].remove(node_id)
            self.graph['edges'] = [edge for edge in self.graph['edges'] if node_id not in edge]

    def add_edge(self, source_id, target_id):
        if source_id in self.graph['nodes'] and target_id in self.graph['nodes']:
            self.graph['edges'].append((source_id, target_id))

    def remove_edge(self, source_id, target_id):
        if (source_id, target_id) in self.graph['edges']:
            self.graph['edges'].remove((source_id, target_id))

    def save_to_json(self, file_path):
        with open(file_path, 'w') as jfile:
            json.dump(self.__graph_state(), jfile)

