using Microsoft.Win32;
using System.Text;

public class RegistryReader
{
    internal static string ReadHklmSubTree(string path)
    {
        var stb = new StringBuilder();
        using (var rKey = Registry.LocalMachine.OpenSubKey(path, RegistryKeyPermissionCheck.ReadSubTree))
        {
            if (rKey == null)
            {
                return null;
            }
            string[] subKeys = rKey.GetSubKeyNames();
            foreach (var subKey in subKeys)
            {
                stb.Append(subKey).Append(", "); // Concatenate subkeys with a delimiter
            }
        }
        return stb.ToString().TrimEnd(' ', ','); // Remove trailing delimiter and spaces
    }
}
