            switch (keyInfo.Key)
            {
                case ConsoleKey.S:
                    StartServer(host);
                    break;
                case ConsoleKey.T:
                    StopServer();
                    break;
            }
        } while (keyInfo.Key != ConsoleKey.Escape);
