export type IEventFunction = (event?: Event) => void;

class EventManager {
  private events: Map<string, IEventFunction[]> = new Map();

  subscribe(eventName: string, callback: IEventFunction): void {
    if (!this.events.has(eventName)) {
      this.events.set(eventName, []);
    }
    this.events.get(eventName)!.push(callback);
  }

  unsubscribe(eventName: string, callback: IEventFunction): void {
    const eventSubscribers = this.events.get(eventName);
    if (eventSubscribers) {
      this.events.set(
        eventName,
        eventSubscribers.filter((cb) => cb !== callback)
      );
    }
  }

  trigger(eventName: string, event?: Event): void {
    const eventSubscribers = this.events.get(eventName);
    if (eventSubscribers) {
      eventSubscribers.forEach((callback) => callback(event));
    }
  }
}

// Usage example
const eventManager = new EventManager();

const callback1: IEventFunction = (event) => {
  console.log("Callback 1 triggered", event);
};

const callback2: IEventFunction = (event) => {
  console.log("Callback 2 triggered", event);
};

eventManager.subscribe("event1", callback1);
eventManager.subscribe("event1", callback2);

eventManager.trigger("event1", new Event("customEvent"));

eventManager.unsubscribe("event1", callback1);

eventManager.trigger("event1", new Event("customEvent"));
```
In this solution, the `EventManager` class manages event subscriptions and triggers as per the given requirements. It uses a `Map` to store event names as keys and arrays of callback functions as values. The `subscribe` method adds callback functions to the corresponding event, the `unsubscribe` method removes callback functions, and the `trigger` method calls all subscribed callback functions for a given event with the optional event object. The usage example demonstrates the functionality of the `EventManager` class.

