```rust
use criterion::{criterion_group, criterion_main, Criterion};

// Quick Sort implementation
fn quick_sort(arr: &mut [i32]) {
    if arr.len() <= 1 {
        return;
    }
    let pivot = arr.len() / 2;
    let mut left = 0;
    let mut right = arr.len() - 1;
    while left <= right {
        while arr[left] < arr[pivot] {
            left += 1;
        }
        while arr[right] > arr[pivot] {
            right -= 1;
        }
        if left <= right {
            arr.swap(left, right);
            left += 1;
            right -= 1;
        }
    }
    if right > 0 {
        quick_sort(&mut arr[0..right + 1]);
    }
    if left < arr.len() {
        quick_sort(&mut arr[left..]);
    }
}

// Merge Sort implementation
fn merge_sort(arr: &mut [i32]) {
    if arr.len() <= 1 {
        return;
    }
    let mid = arr.len() / 2;
    merge_sort(&mut arr[..mid]);
    merge_sort(&mut arr[mid..]);
    let mut result = Vec::with_capacity(arr.len());
    let (mut left, mut right) = (0, mid);
    while left < mid && right < arr.len() {
        if arr[left] <= arr[right] {
            result.push(arr[left]);
            left += 1;
        } else {
            result.push(arr[right]);
            right += 1;
        }
    }
    result.extend_from_slice(&arr[left..mid]);
    result.extend_from_slice(&arr[right..]);
    arr.copy_from_slice(&result);
}

fn sorting_benchmarks(c: &mut Criterion) {
    let mut data_quick_sort = vec![5, 3, 8, 2, 1, 4, 6, 7];
    c.bench_function("Quick Sort", |b| b.iter(|| quick_sort(&mut data_quick_sort)));

    let mut data_merge_sort = vec![5, 3, 8, 2, 1, 4, 6, 7];
    c.bench_function("Merge Sort", |b| b.iter(|| merge_sort(&mut data_merge_sort)));
}

criterion_group!(benches, sorting_benchmarks);
criterion_main!(benches);
```

In this solution, we first implement the Quick Sort and Merge Sort algorithms in Rust. Then, we define a benchmark group using the `criterion` crate, where we measure the performance of the Quick Sort and Merge Sort algorithms. Finally, we run the benchmarks using the `criterion_main!` macro, which outputs the benchmark results, including the average time taken for each algorithm.

