class MessageStorage:
    def __init__(self):
        self.messages = {}
        self.lock = Lock()

    def add_message(self, header, body):
        with self.lock:
            key = str(uuid.uuid4())
            self.messages[key] = {'header': header, 'body': body}
            return key

    def replace_message(self, key, header, body):
        with self.lock:
            if key in self.messages:
                self.messages[key] = {'header': header, 'body': body}
            else:
                raise KeyError("Message with key {} does not exist".format(key))

# Instantiate the message storage
