func countPairsWithSum(_ nums: [Int], _ target: Int) -> Int {
    var count = 0
    var numSet = Set<Int>()

    for num in nums {
        let complement = target - num
        if numSet.contains(complement) {
            count += 1
        }
        numSet.insert(num)
    }

    return count
