public class Message
{
    public string Content { get; set; }
}

public interface IMessagePipe
{
    void ProcessMessage(Message message);
}

public class MessagePipe : IMessagePipe
{
    private List<Func<Message, bool>> filters;
    private List<Func<Message, Message>> transformers;
    private Action<Exception, Message> errorHandler;

    public MessagePipe(List<Func<Message, bool>> filters, List<Func<Message, Message>> transformers, Action<Exception, Message> errorHandler)
    {
        this.filters = filters;
        this.transformers = transformers;
        this.errorHandler = errorHandler;
    }

    public void ProcessMessage(Message message)
    {
        try
        {
            if (filters.All(filter => filter(message)))
            {
                foreach (var transformer in transformers)
                {
                    message = transformer(message);
                }
                Console.WriteLine("Message processed: " + message.Content);
            }
            else
            {
                Console.WriteLine("Message filtered out");
            }
        }
        catch (Exception ex)
        {
            errorHandler(ex, message);
        }
    }
}

public class MessagePipeConfigurator : IMessagePipeConfigurator
{
    private List<Func<Message, bool>> filters = new List<Func<Message, bool>>();
    private List<Func<Message, Message>> transformers = new List<Func<Message, Message>>();
    private Action<Exception, Message> errorHandler;

    public IMessagePipeConfigurator AddFilter(Func<Message, bool> filter)
    {
        filters.Add(filter);
        return this;
    }

    public IMessagePipeConfigurator AddTransformer(Func<Message, Message> transformer)
    {
        transformers.Add(transformer);
        return this;
    }

    public IMessagePipeConfigurator SetErrorHandler(Action<Exception, Message> errorHandler)
    {
        this.errorHandler = errorHandler;
        return this;
    }

    public IMessagePipe Build()
    {
        return new MessagePipe(filters, transformers, errorHandler);
    }
}

public class Program
{
    public static void Main()
    {
        IMessagePipeConfigurator configurator = new MessagePipeConfigurator();
        IMessagePipe messagePipe = configurator
            .AddFilter(msg => msg.Content.Length > 5)
            .AddTransformer(msg =>
            {
                msg.Content = msg.Content.ToUpper();
                return msg;
            })
            .SetErrorHandler((ex, msg) => Console.WriteLine("Error processing message: " + ex.Message))
            .Build();

        Message message1 = new Message { Content = "Hello, World!" };
        Message message2 = new Message { Content = "Hi" };

        messagePipe.ProcessMessage(message1);
        messagePipe.ProcessMessage(message2);
    }
}
