public class EdDSAKeyPairManager {
    private EdDSAPrivateKey privateKey;
    private EdDSAPublicKey publicKey;

    public EdDSAKeyPairManager(String hex) {
        byte[] b = Utils.hexStringToByteArray(hex);

        KeyPairGenerator keyGen = new KeyPairGenerator();
        keyGen.initialize();
        java.security.KeyPair keyPair = keyGen.generateKeyPair();

        this.privateKey = (EdDSAPrivateKey) keyPair.getPrivate();
        this.publicKey = (EdDSAPublicKey) keyPair.getPublic();
    }

    public byte[] sign(byte[] data) {
        try {
            Signature sgr = Signature.getInstance("EdDSA");
            sgr.initSign(privateKey);
            sgr.update(data);
            return sgr.sign();
        } catch (Exception e) {
            e.printStackTrace();
            return null;
        }
    }

    public boolean verify(byte[] data, byte[] signature) {
        try {
            Signature sgr = Signature.getInstance("EdDSA");
            sgr.initVerify(publicKey);
            sgr.update(data);
            return sgr.verify(signature);
        } catch (Exception e) {
            e.printStackTrace();
            return false;
        }
    }
}
