```csharp
using System;
using System.Reflection;

public class Constructor<TObject>
{
    private Type _type;
    private bool _includePrivate;
    private Type[] _argumentTypes;

    public Constructor(Type type, bool includePrivate, params Type[] argumentTypes)
    {
        _type = type;
        _includePrivate = includePrivate;
        _argumentTypes = argumentTypes;
    }

    public TObject Invoke(params object[] arguments)
    {
        ConstructorInfo constructor = _type.GetConstructor(
            BindingFlags.Instance | BindingFlags.Public | (_includePrivate ? BindingFlags.NonPublic : 0),
            null, _argumentTypes, null);

        if (constructor == null)
        {
            throw new MissingMethodException($"Constructor with specified argument types not found for type {_type.Name}");
        }

        return (TObject)constructor.Invoke(arguments);
    }
}
```

