import * as fs from 'fs';

function resolveModuleDependencies(moduleName: string, resolvedModules: Set<string> = new Set()): string[] {
  if (resolvedModules.has(moduleName)) {
    return [];
  }

  resolvedModules.add(moduleName);

  const modulePath = `./lib/${moduleName}`;
  const moduleContent = fs.readFileSync(modulePath, 'utf8');
  const dependencies: string[] = [];

  const exportStatements = moduleContent.match(/export \* from '(.*)';/g) || [];
  for (const statement of exportStatements) {
    const dependency = statement.match(/export \* from '(.*)';/)![1];
    dependencies.push(dependency);
    const transitiveDependencies = resolveModuleDependencies(dependency, resolvedModules);
    dependencies.push(...transitiveDependencies);
  }

  return dependencies;
}

