import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import java.util.ArrayList;
import java.util.List;
import java.util.regex.Pattern;

public class FileSearchUtility {
    private String directory;
    private String fileName;
    private boolean useMask;
    private boolean useFullMatch;
    private boolean useRegex;
    private String outputFile;

    public FileSearchUtility(String[] args) {
        parseArguments(args);
    }

    private void parseArguments(String[] args) {
        for (int i = 0; i < args.length; i++) {
            switch (args[i]) {
                case "-d":
                    directory = args[++i];
                    break;
                case "-n":
                    fileName = args[++i];
                    break;
                case "-m":
                    useMask = true;
                    break;
                case "-f":
                    useFullMatch = true;
                    break;
                case "-r":
                    useRegex = true;
                    break;
                case "-o":
                    outputFile = args[++i];
                    break;
                default:
                    System.out.println("Invalid option: " + args[i]);
                    System.exit(1);
            }
        }
    }

    public void searchFiles() {
        File dir = new File(directory);
        File[] files = dir.listFiles();
        List<String> results = new ArrayList<>();

        if (files != null) {
            for (File file : files) {
                if (matchesCriteria(file.getName())) {
                    results.add(file.getAbsolutePath());
                }
            }
        }

        if (outputFile != null) {
            writeResultsToFile(results);
        } else {
            for (String result : results) {
                System.out.println(result);
            }
        }
    }

    private boolean matchesCriteria(String fileName) {
        if (useMask) {
            String regex = this.fileName.replace(".", "\\.").replace("*", ".*");
            return Pattern.matches(regex, fileName);
        } else if (useFullMatch) {
            return fileName.equals(this.fileName);
        } else if (useRegex) {
            return Pattern.matches(this.fileName, fileName);
        } else {
            return fileName.contains(this.fileName);
        }
    }

    private void writeResultsToFile(List<String> results) {
        try (FileWriter writer = new FileWriter(outputFile)) {
            for (String result : results) {
                writer.write(result + System.lineSeparator());
            }
        } catch (IOException e) {
            System.err.println("Error writing to file: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        FileSearchUtility fileSearchUtility = new FileSearchUtility(args);
        fileSearchUtility.searchFiles();
    }
}
```

This Java program provides a command-line file search utility that supports the specified options. It parses the command-line arguments, performs the file search based on the criteria, and optionally writes the results to a file. The `matchesCriteria` method handles the different matching options (-m, -f, -r) for file names. The `writeResultsToFile` method writes the search results to the specified output file. The `main` method initializes the utility and triggers the file search.

