use std::fs;
use std::path::Path;

fn is_fibonacci(num: u64) -> bool {
    let mut a = 0;
    let mut b = 1;
    while b < num {
        let temp = b;
        b = a + b;
        a = temp;
    }
    b == num
}

fn sum_fibonacci_from_directory(directory_path: &str) -> Result<u64, String> {
    let path = Path::new(directory_path);
    if !path.is_dir() {
        return Err("Invalid directory path".to_string());
    }

    let mut sum = 0;
    for entry in fs::read_dir(path).map_err(|e| e.to_string())? {
        let entry = entry.map_err(|e| e.to_string())?;
        let file_content = fs::read_to_string(entry.path()).map_err(|e| e.to_string())?;
        for word in file_content.split_whitespace() {
            if let Ok(num) = word.parse::<u64>() {
                if is_fibonacci(num) {
                    sum += num;
                }
            }
        }
    }
    Ok(sum)
}
```

This solution first checks if the provided directory path is valid. Then, it iterates through the files in the directory, reads their content, and calculates the sum of Fibonacci numbers present in the files. The `is_fibonacci` function is used to check if a number is a Fibonacci number. If any error occurs during file reading or parsing, it returns an error message. Otherwise, it returns the sum of Fibonacci numbers as a result.

