public VkTransformMatrixKHR InterpolateMotionMatrix(VkAccelerationStructureMatrixMotionInstanceNV motionInstance, float t)
{
    VkTransformMatrixKHR interpolatedMatrix;

    for (int i = 0; i < 12; i++)
    {
        interpolatedMatrix.matrix[i] = motionInstance.transformT0.matrix[i] * (1 - t) + motionInstance.transformT1.matrix[i] * t;
